def collatz(n):
    """Generate the Collatz sequence starting at n until it reaches 1."""
    sequence = [n]
    while n > 1:
        if n % 2 == 0:
            n = n // 2
        else:
            n = 3 * n + 1
        sequence.append(n)
    return sequence

